<?php
declare(strict_types=1);
require_once __DIR__.'/_funding.php';
require_once __DIR__.'/_package_webhook.php';
require_once dirname(__DIR__).'/payments/_payments.php';
mg_require_method('POST');
$provider=trim((string)($_GET['provider']??'stripe'))?:'stripe';
$payload=file_get_contents('php://input')?:'';
$serverKey='HTTP_'.'STRIPE'.'_SIGNATURE';
$sig=(string)($_SERVER[$serverKey]??$_SERVER['HTTP_X_MG_SIGNATURE']??'');
$event=json_decode($payload,true);
if(!is_array($event)||!mg_payment_verify_signature($provider,$payload,$sig))mg_fail('Invalid subscription payment webhook.',401);
$eventId=trim((string)($event['id']??''));$type=trim((string)($event['type']??''));if($eventId===''||$type==='')mg_fail('Invalid subscription payment event.',422);
$pdo=mg_db();$payloadHash=hash('sha256',$payload);
try{$pdo->beginTransaction();$existingStmt=$pdo->prepare('SELECT signature_valid,status,payload_hash,event_type FROM payment_webhook_events WHERE provider_key=? AND provider_event_id=? LIMIT 1 FOR UPDATE');$existingStmt->execute([$provider,$eventId]);$existing=$existingStmt->fetch(PDO::FETCH_ASSOC);if($existing){$same=(int)$existing['signature_valid']===1&&hash_equals((string)$existing['payload_hash'],$payloadHash)&&hash_equals((string)$existing['event_type'],$type);if(!$same)throw new RuntimeException('Webhook event conflicts with an existing provider event.');if(in_array((string)$existing['status'],['processed','ignored'],true)){$pdo->commit();mg_ok(['duplicate'=>true,'status'=>(string)$existing['status']],'Subscription payment webhook already received.');}$pdo->prepare("UPDATE payment_webhook_events SET status='processing',failure_message=NULL,received_at=NOW() WHERE provider_key=? AND provider_event_id=?")->execute([$provider,$eventId]);}else{$pdo->prepare("INSERT INTO payment_webhook_events (public_id,provider_key,provider_event_id,event_type,signature_valid,status,payload_hash,payload_json,received_at) VALUES (?,?,?,?,1,'processing',?,?,NOW())")->execute([mg_public_uuid(),$provider,$eventId,$type,$payloadHash,$payload]);}$packageResult=mg_subscription_package_webhook_try_process($pdo,$provider,$event);$result=null;if($packageResult!==null){$result=['package_checkout'=>$packageResult];}else{$data=is_array($event['data']??null)?$event['data']:[];$object=is_array($data['object']??null)?$data['object']:$data;$paymentIdValue=$object['payment_id']??$object['payment_intent']??$object['id']??'';$paymentId=is_array($paymentIdValue)?trim((string)($paymentIdValue['id']??'')):trim((string)$paymentIdValue);$successTypes=['payment_intent.succeeded','charge.succeeded','subscription.payment_succeeded'];$failureTypes=['payment_intent.payment_failed','charge.failed','subscription.payment_failed'];if($paymentId!==''&&in_array($type,array_merge($successTypes,$failureTypes),true)){$stmt=$pdo->prepare("SELECT a.id attempt_id,a.status attempt_status,s.id subscription_id,s.public_id subscription_public_id,s.subscriber_user_id,s.recipient_user_id,s.target_type,s.target_reference,s.amount_cents,s.currency,s.funding_type,s.status,s.current_period_start,s.current_period_end,s.next_billing_at,s.cancel_at_period_end,s.retry_count,s.trial_ends_at,s.initial_payment_required,s.funded_at,s.activated_at,p.interval_unit,p.interval_count FROM subscription_attempts a INNER JOIN subscriptions s ON s.id=a.subscription_id INNER JOIN subscription_plans p ON p.id=s.plan_id WHERE a.provider_payment_id=? LIMIT 1 FOR UPDATE");$stmt->execute([$paymentId]);$row=$stmt->fetch(PDO::FETCH_ASSOC);if(!$row)throw new RuntimeException('Subscription payment attempt not found.');$result=in_array($type,$successTypes,true)?mg_subscription_apply_payment_success($pdo,$row,$paymentId):mg_subscription_apply_payment_failure($pdo,$row,$paymentId,(string)($object['failure_message']??$object['last_payment_error']['message']??'Provider reported payment failure.'));}else{$result=['ignored'=>true,'reason'=>'not_a_package_or_support_subscription_event'];}}$status=isset($result['ignored'])?'ignored':'processed';$pdo->prepare('UPDATE payment_webhook_events SET status=?,processed_at=NOW(),failure_message=NULL WHERE provider_key=? AND provider_event_id=?')->execute([$status,$provider,$eventId]);$pdo->commit();mg_ok(['received'=>true,'result'=>$result],'Subscription payment webhook processed.');}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();try{$pdo->prepare("UPDATE payment_webhook_events SET status='failed',failure_message=? WHERE provider_key=? AND provider_event_id=?")->execute([mb_substr($e->getMessage(),0,500),$provider,$eventId]);}catch(Throwable){}mg_fail('Unable to process subscription payment webhook.',500);}
